tool.commandText:
{"content":"% Custom Commands for Micro Soldering Notes

% Component reference: \ic{component}{type}{page}
\newcommand{\ic}[3]{\textbf{#1} (#2) - Page #3}

% Signal name: \signal{SIGNAL_NAME}
\newcommand{\signal}[1]{\texttt{#1}}

% Power rail: \rail{P3V3A}
\newcommand{\rail}[1]{\textcolor{blue}{\texttt{#1}}}

% FlexBV reference: \flexbv{U300}
\newcommand{\flexbv}[1]{\textit{FlexBV: #1}}

% Lab task box: \labtask{Measure voltage at C304}
\newcommand{\labtask}[1]{\fbox{\parbox{\dimexpr\linewidth-2\fboxsep-2\fboxrule\relax}{\textbf{LAB:} #1}}}

% Mastery marker: \mastered{2026-03-10}
\newcommand{\mastered}[1]{\marginnote{Mastered: #1}}

% Pin reference: \pin{46}{KBC_PWR_ON}
\newcommand{\pin}[2]{Pin #1 (\signal{#2})}

% Page reference in schematic: \schematic{46}{C5}
\newcommand{\schematic}[2]{Page #1, Section #2}

% Voltage value: \voltage{3.3}
\newcommand{\voltage}[1]{\SI{#1}{\volt}}

% Current value: \current{500}{\milli}
\newcommand{\current}[2]{\SI{#1}{#2\ampere}}

% Resistance value: \resistance{10}{\kilo}
\newcommand{\resistance}[2]{\SI{#1}{#2\ohm}}

% Capacitance value: \capacitance{100}...

