tool.commandText:
{"content":"% Visual Styling for Micro Soldering Notes

% Section formatting
\titleformat{\chapter}[display]
    {\normalfont\huge\bfseries\color{blue}}
    {\chaptertitlename\ \thechapter}
    {20pt}
    {\Huge}

\titleformat{\section}
    {\normalfont\Large\bfseries\color{black}}
    {\thesection}
    {1em}
    {}

\titleformat{\subsection}
    {\normalfont\large\bfseries}
    {\thesubsection}
    {1em}
    {}

% Itemize styling
\setlist[itemize]{
    leftmargin=*,
    label=\textcolor{blue}{\textbullet}
}

\setlist[enumerate]{
    leftmargin=*,
    label=\textcolor{blue}{\arabic*.}
}

% Code listing style
\lstset{
    basicstyle=\ttfamily\small,
    keywordstyle=\color{blue},
    stringstyle=\color{red},
    commentstyle=\color{gray},
    breaklines=true,
    breakatwhitespace=true,
    frame=single,
    backgroundcolor=\color{gray!10}
}

% Header and footer
\pagestyle{fancy}
\fancyhf{}
\fancyhead[L]{\leftmark}
\fancyhead[R]{\thepage}
\renewcommand{\headrulewidth}{0.4pt}

% Hyperlink colors
\definecolor{linkblue}{RGB}{0, 102, 204}
\definecolor{signalgreen}{RGB}{0, 153, 76}
\defin...

